// src/lib/api.ts
export async function fetchGpuPods(status?: string) {
  const params = status ? `?status=${status}` : "";
  const res = await fetch(`${API_BASE}/api/gpu-pods${params}`);
  return res.json();
}

export async function terminatePod(podId: string) {
  const res = await fetch(`${API_BASE}/api/gpu-pods/${podId}`, {
    method: "DELETE",
  });
  if (!res.ok) throw new Error("Failed to terminate pod");
}
