Implement real-time updates using SWR polling.

## Why Polling (not WebSockets)
- Simpler implementation
- Works with any deployment (no sticky sessions)
- Sufficient for this use case (not real-time chat)
- Hatchet dashboard uses WebSockets if you need detailed logs

## SWR Configuration
```typescript
// src/lib/hooks.ts
import useSWR from "swr";

const fetcher = (url: string) => fetch(url).then((res) => res.json());

// Workflow list - poll every 5 seconds
export function useWorkflows(status?: string) {
  const params = new URLSearchParams();
  if (status) params.set("status", status);

  return useSWR(
    `/api/workflows?${params}`,
    fetcher,
    {
      refreshInterval: 5000,
      revalidateOnFocus: true,
    }
  );
}

// Workflow detail - poll every 2 seconds (more frequent for running workflows)
export function useWorkflow(id: string) {
  const { data, error, ...rest } = useSWR(`/api/workflows/${id}`, fetcher, {
    refreshInterval: (data) => {
      // Poll faster for running workflows
      if (data?.status === "running") return 2000;
      // Slow poll for completed/failed
      return 10000;
    },
    revalidateOnFocus: true,
  });

  return { data, error, ...rest };
}

// GPU pods - poll every 10 seconds
export function useGpuPods(status?: string) {
  const params = new URLSearchParams();
  if (status) params.set("status", status);

  return useSWR(
    `/api/gpu-pods?${params}`,
    fetcher,
    { refreshInterval: 10000 }
  );
}
```

## Loading and Error States
```typescript
// src/components/data-loader.tsx
interface DataLoaderProps<T> {
  data: T | undefined;
  error: Error | undefined;
  isLoading: boolean;
  children: (data: T) => React.ReactNode;
}

export function DataLoader<T>({ data, error, isLoading, children }: DataLoaderProps<T>) {
  if (isLoading) return <Skeleton />;
  if (error) return <ErrorCard error={error} />;
  if (!data) return <EmptyState />;
  return children(data);
}
```

## Optimistic Updates
```typescript
// For actions like terminate pod
async function handleTerminate(podId: string) {
  // Optimistically update UI
  mutate(
    "/api/gpu-pods",
    (data) => ({
      ...data,
      items: data.items.filter((p) => p.id !== podId),
    }),
    false
  );

  // Make API call
  await terminatePod(podId);

  // Revalidate
  mutate("/api/gpu-pods");
}
```

