### Cost Estimate
```typescript
// Rough cost estimation based on word count
function estimateCost(wordCount: number, generateImages: boolean) {
  const ttsMinutes = wordCount / 150;  // ~150 words per minute
  const ttsCost = ttsMinutes * 0.10;   // $0.10 per minute (rough)
  const imageCost = generateImages ? (wordCount / 500) * 0.05 : 0;  // ~1 image per 500 words
  const gpuCost = (ttsMinutes + (generateImages ? 5 : 0)) * 0.01;  // Rough GPU time
  return { tts: ttsCost, images: imageCost, gpu: gpuCost, total: ttsCost + imageCost + gpuCost };
}
